// ---------- Orders ----------
export const apiCreateOrder = async (payload) => {
  // If a customer is signed in, attach their bearer so the backend can link
  // the order to their account (powers /api/orders/mine).
  const headers = buildHeaders(false, true);
  const ct = getCustomerBearer();
  if (ct) headers["Authorization"] = `Bearer ${ct}`;
  const resp = await fetch(`${API}/orders`, {
    method: "POST",
    headers,
    body: JSON.stringify(payload),
  });
  return handle(resp);
};

