// ---------- Upload ----------
// Accepts a dataURL or a plain http(s) URL.
// - dataURL → uploads to backend, returns absolute image URL.
// - http(s) URL → passes through.
export const apiUploadIfDataUrl = async (value) => {
  if (!value) return "";
  const v = String(value).trim();
  if (!v.startsWith("data:")) return v;
  const resp = await fetch(`${API}/upload/image`, {
    method: "POST",
    headers: buildHeaders(true, true),
    body: JSON.stringify({ data_url: v }),
  });
  const data = await handle(resp);
  return absoluteImage(data?.url || "");
};

