const EMPTY_FORM = {
  name: "",
  phone: "",
  email: "",
  altPhone: "",
  pincode: "",
  state: "",
  city: "",
  house: "",
  colony: "",
};

// Accepts a `target` of the form { product } (Buy Now) or { items } (Cart).
export const CheckoutDialog = ({ target, open, onClose, onPlaced }) => {
  const isCart = Array.isArray(target?.items);
  const items = useMemo(() => {
    if (isCart) return target.items;
    if (target?.product) {
      const p = target.product;
      return [
        {
          ...p,
          qty: 1,
          size: p.selectedSize || p.size || "Free Size",
          color: p.selectedColor || null,
          colorLabel: p.selectedColorLabel || null,
        },
      ];
    }
    return [];
  }, [target, isCart]);

  const total = useMemo(
    () =>
      items.reduce(
        (acc, i) => acc + (Number(i.price) || 0) * (Number(i.qty) || 1),
        0,
      ),
    [items],
  );

  const [form, setForm] = useState(EMPTY_FORM);
  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(null);
  const [prefilled, setPrefilled] = useState(false);

  // P3a — when a signed-in customer opens checkout, prefill the empty fields
  // from their cached profile. Only fills EMPTY fields, never overwrites
  // anything the user has already typed. Stops once the form has been touched
  // so re-opens don't clobber edits during the same session.
  useEffect(() => {
    if (!open || prefilled) return;
    const customer = getCachedCustomer();
    if (!customer) return;
    const phone =
      typeof customer.phone === "string"
        ? customer.phone.replace(/\D+/g, "").slice(-10)
        : "";
    setForm((p) => {
      const next = { ...p };
      if (!next.name && customer.name) next.name = customer.name;
      if (!next.phone && phone) next.phone = phone;
      return next;
    });
    setPrefilled(true);
  }, [open, prefilled]);

  // Reset the prefill latch when the dialog closes so the next open re-fills
  // fresh customer data.
  useEffect(() => {
    if (!open) setPrefilled(false);
  }, [open]);

  // If the customer signs in/out WHILE the dialog is open, refresh once.
  useEffect(() => {
    if (!open) return;
    const onChange = () => {
      const c = getCachedCustomer();
      if (!c) return;
      const phone = typeof c.phone === "string" ? c.phone.replace(/\D+/g, "").slice(-10) : "";
      setForm((p) => ({
        ...p,
        name: p.name || c.name || "",
        phone: p.phone || phone,
      }));
    };
    window.addEventListener(CUSTOMER_CHANGE_EVENT, onChange);
    return () => window.removeEventListener(CUSTOMER_CHANGE_EVENT, onChange);
  }, [open]);

  const update = (k) => (e) =>
    setForm((p) => ({ ...p, [k]: e.target.value }));

  const validate = () => {
    const e = {};
    if (!form.name.trim() || form.name.trim().length < 2)
      e.name = "Enter your full name";
    if (!/^[6-9]\d{9}$/.test(form.phone.trim()))
      e.phone = "Enter a valid 10-digit Indian mobile";
    if (form.altPhone.trim() && !/^[6-9]\d{9}$/.test(form.altPhone.trim()))
      e.altPhone = "Alt mobile is invalid";
    if (!/^\d{6}$/.test(form.pincode.trim()))
      e.pincode = "6-digit pincode";
    if (!form.state) e.state = "Select your state";
    if (!form.city.trim() || form.city.trim().length < 2)
      e.city = "Enter your city";
    if (!form.house.trim() || form.house.trim().length < 2)
      e.house = "House / Building required";
    if (!form.colony.trim() || form.colony.trim().length < 2)
      e.colony = "Colony / Area required";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const submit = async (ev) => {
    ev.preventDefault();
    if (submitting || success) return;
    if (!validate()) return;

    setSubmitting(true);
    try {
      const order = await addOrder(
        isCart
          ? { items, ...form }
          : { product: items[0], ...form },
      );
      // Silent auto-signup: creates a customer account behind the scenes so
      // the browser remembers them for next visit. No login screen shown.
      await silentSignup({
        email: form.email,
        phone: form.phone,
        name: form.name,
      });
      const notify = await sendOrderPlacedNotification({
        phone: form.phone,
        order,
      });
      setSuccess({ order, notify });
      onPlaced?.({ wasCart: isCart });
    } catch (err) {
      // Surface the failure so the user can retry instead of being stuck.
      setErrors((p) => ({
        ...p,
        _root: err?.message || "Could not place order. Please try again.",
      }));
    } finally {
      setSubmitting(false);
    }
  };

  const close = () => {
    setSuccess(null);
    setForm(EMPTY_FORM);
    setErrors({});
    onClose();
  };

  return (
    <AnimatePresence>
      {open && items.length > 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-stretch sm:items-center justify-center p-0 sm:p-6 bg-black/55 backdrop-blur-sm"
          onClick={close}
          data-testid={CHECKOUT.modal}
        >
          <motion.div
            initial={{ y: 40, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 40, opacity: 0 }}
            transition={{ type: "spring", stiffness: 220, damping: 24 }}
            onClick={(e) => e.stopPropagation()}
            className="relative w-full sm:max-w-3xl bg-white sm:rounded-3xl shadow-[0_30px_80px_rgba(0,0,0,0.22)] overflow-hidden max-h-[100vh] sm:max-h-[92vh] flex flex-col"
          >
            {/* Gold hairline */}
            <div className="h-[2px] w-full bg-gradient-to-r from-transparent via-[#E0B53C]/70 to-transparent" />

            <button
              onClick={close}
              data-testid={CHECKOUT.closeBtn}
              aria-label="close"
              className="absolute top-4 right-4 z-10 w-9 h-9 rounded-full bg-white/95 hover:bg-neutral-100 flex items-center justify-center shadow-sm border border-black/5 transition-colors"
            >
              <X size={16} strokeWidth={1.8} />
            </button>

            {success ? (
              <SuccessView
                order={success.order}
                notify={success.notify}
                items={items}
                onClose={close}
              />
            ) : (
              <CheckoutForm
                items={items}
                total={total}
                form={form}
                update={update}
                errors={errors}
                submitting={submitting}
                onSubmit={submit}
              />
            )}
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

