const Field = ({
  label,
  value,
  onChange,
  error,
  placeholder,
  testId,
  inputMode,
  maxLength,
  prefix,
  className = "",
}) => (
  <label className={`block ${className}`}>
    <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5 font-medium">
      {label}
    </span>
    <div
      className={`flex items-stretch overflow-hidden rounded-xl bg-white border ${error ? "border-red-400" : "border-black/10"} focus-within:border-[#0B0C10] focus-within:ring-1 focus-within:ring-[#0B0C10] transition-all`}
    >
      {prefix && (
        <span className="px-3 flex items-center text-sm text-neutral-500 bg-neutral-50 border-r border-black/5">
          {prefix}
        </span>
      )}
      <input
        data-testid={testId}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        inputMode={inputMode}
        maxLength={maxLength}
        className="flex-1 outline-none px-3 py-3 text-sm text-[#0B0C10] placeholder:text-neutral-400 bg-transparent"
      />
    </div>
    {error && (
      <span className="block text-[11px] text-red-500 mt-1">{error}</span>
    )}
  </label>
);

const SelectField = ({
  label,
  value,
  onChange,
  error,
  options,
  placeholder,
  testId,
  className = "",
}) => (
  <label className={`block ${className}`}>
    <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5 font-medium">
      {label}
    </span>
    <select
      data-testid={testId}
      value={value}
      onChange={onChange}
      className={`w-full bg-white border ${error ? "border-red-400" : "border-black/10"} focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-3 text-sm text-[#0B0C10] transition-all appearance-none`}
    >
      <option value="">{placeholder}</option>
      {options.map((o) => (
        <option key={o} value={o}>
          {o}
        </option>
      ))}
    </select>
    {error && (
      <span className="block text-[11px] text-red-500 mt-1">{error}</span>
    )}
  </label>
);
